'use client'

import { useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'
import { useParams, useRouter } from 'next/navigation'
import Link from 'next/link'
import VideoUpload from '@/components/VideoUpload'
import CourseFramework, { courseFramework } from '@/components/CourseFramework'

// Note: Check that CourseFramework returns JSX, not void

interface Course {
  id: string
  title: string
  description: string
  video_url?: string
  checkpoints?: string
  pdfs?: string
  framework?: string
}

export default function CourseEditor() {
  const params = useParams()
  const courseId = params.id as string
  const router = useRouter()

  const [course, setCourse] = useState<Course | null>(null)
  const [frameworkData, setFrameworkData] = useState<any[]>(courseFramework) // default structure
  const [loading, setLoading] = useState(true)
  const [user, setUser] = useState<any>(null)
  const [videoUrl, setVideoUrl] = useState('')
  const [checkpoints, setCheckpoints] = useState<string[]>([''])
  const [pdfs, setPdfs] = useState<{ name: string; url: string }[]>([])

  useEffect(() => {
    checkAuth()
  }, [])

  const checkAuth = async () => {
    try {
      const result = await supabase.auth.getSession()
      const session = result.data?.session

      if (!session) {
        router.push('/login')
        return
      }

      setUser(session.user)
      fetchCourse(session.user.id)
    } catch (error) {
      console.error('Auth error:', error)
      router.push('/login')
    }
  }

  const fetchCourse = async (userId: string) => {
    try {
      const { data: courseData, error } = await supabase
        .from('courses')
        .select('*')
        .eq('id', courseId)
        .eq('instructor_id', userId)
        .single()

      if (error) {
        console.error('Fetch course error:', error)
        setLoading(false)
        return
      }

      if (courseData) {
        setCourse(courseData)
        setVideoUrl(courseData.video_url || '')
        setCheckpoints(courseData.checkpoints ? JSON.parse(courseData.checkpoints) : [''])
        setPdfs(courseData.pdfs ? JSON.parse(courseData.pdfs) : [])
        if (courseData.framework) {
          try {
            setFrameworkData(JSON.parse(courseData.framework))
          } catch {
            // ignore parse errors
          }
        }
      }
      setLoading(false)
    } catch (error) {
      console.error('Course fetch exception:', error)
      setLoading(false)
    }
  }

  const handleAddCheckpoint = () => {
    setCheckpoints([...checkpoints, ''])
  }

  const handleCheckpointChange = (index: number, value: string) => {
    const updated = [...checkpoints]
    updated[index] = value
    setCheckpoints(updated)
  }

  const handleRemoveCheckpoint = (index: number) => {
    const updated = checkpoints.filter((_, i) => i !== index)
    setCheckpoints(updated)
  }

  const handleSaveCheckpoints = async () => {
    const filteredCheckpoints = checkpoints.filter(cp => cp.trim())

    if (filteredCheckpoints.length === 0) {
      alert('Please add at least one checkpoint')
      return
    }

    const { error } = await supabase
      .from('courses')
      .update({ checkpoints: JSON.stringify(filteredCheckpoints) })
      .eq('id', courseId)

    if (!error) {
      alert('Checkpoints saved!')
    }
  }

  const handlePdfUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return

    if (!file.type.includes('pdf')) {
      alert('Please upload a PDF file')
      return
    }

    const fileName = `${courseId}/${Date.now()}_${file.name}`

    const { error: uploadError } = await supabase.storage
      .from('course-materials')
      .upload(fileName, file)

    if (uploadError) {
      console.error('Upload error:', uploadError)
      alert('Failed to upload PDF')
      return
    }

    const { data: { publicUrl } } = supabase.storage
      .from('course-materials')
      .getPublicUrl(fileName)

    const newPdfs = [...pdfs, { name: file.name, url: publicUrl }]
    setPdfs(newPdfs)

    const { error: updateError } = await supabase
      .from('courses')
      .update({ pdfs: JSON.stringify(newPdfs) })
      .eq('id', courseId)

    if (!updateError) {
      alert('PDF uploaded!')
      e.target.value = ''
    }
  }

  const handleRemovePdf = async (index: number) => {
    const updated = pdfs.filter((_, i) => i !== index)
    setPdfs(updated)

    const { error } = await supabase
      .from('courses')
      .update({ pdfs: JSON.stringify(updated) })
      .eq('id', courseId)

    if (!error) {
      alert('PDF removed!')
    }
  }

  if (loading) return <div className="min-h-screen flex items-center justify-center">Loading...</div>
  if (!course) return <div className="min-h-screen flex items-center justify-center">Course not found</div>

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <Link href="/dashboard" className="text-blue-600 hover:underline">
            ← Back to Dashboard
          </Link>
          <h1 className="text-2xl font-bold">{course.title}</h1>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="space-y-8">
          {/* Course Framework Section */}
          <div className="bg-gradient-to-br from-blue-50 to-indigo-50 p-8 rounded-lg shadow">
            <h2 className="text-2xl font-bold mb-6">📚 Course Structure</h2>
            <CourseFramework
              courseId={courseId}
              initialFramework={frameworkData}
              onFrameworkSave={async updated => {
                await supabase
                  .from('courses')
                  .update({ framework: JSON.stringify(updated) })
                  .eq('id', courseId)
                setFrameworkData(updated)
              }}
            />
          </div>

          {/* Video Section */}
          <VideoUpload
            courseId={courseId}
            currentVideoUrl={videoUrl}
            onVideoUploaded={(newUrl) => {
              setVideoUrl(newUrl)
              if (user && user.id) {
                fetchCourse(user.id)
              }
            }}
          />

          {/* Lesson Checkpoints Section */}
          <div className="bg-white p-8 rounded-lg shadow">
            <h2 className="text-2xl font-bold mb-4">✓ Lesson Checkpoints</h2>
            <div className="space-y-4">
              {checkpoints.map((checkpoint, index) => (
                <div key={index} className="flex gap-2">
                  <input
                    type="text"
                    value={checkpoint}
                    onChange={(e) => handleCheckpointChange(index, e.target.value)}
                    placeholder="Enter checkpoint (e.g., 'Introduction completed')"
                    className="flex-1 px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                  {checkpoints.length > 1 && (
                    <button
                      onClick={() => handleRemoveCheckpoint(index)}
                      className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700"
                    >
                      Remove
                    </button>
                  )}
                </div>
              ))}
              <div className="flex gap-2">
                <button
                  onClick={handleAddCheckpoint}
                  className="flex-1 bg-gray-600 text-white px-4 py-2 rounded-lg hover:bg-gray-700"
                >
                  Add Checkpoint
                </button>
                <button
                  onClick={handleSaveCheckpoints}
                  className="flex-1 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700"
                >
                  Save Checkpoints
                </button>
              </div>
            </div>
          </div>

          {/* PDF Upload Section */}
          <div className="bg-white p-8 rounded-lg shadow">
            <h2 className="text-2xl font-bold mb-4">📄 Course Materials (PDF)</h2>
            <div className="space-y-4">
              <div className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center">
                <label className="cursor-pointer">
                  <div className="text-4xl mb-2">📁</div>
                  <p className="text-gray-600 mb-2">Click to upload PDF</p>
                  <input
                    type="file"
                    accept=".pdf"
                    onChange={handlePdfUpload}
                    className="hidden"
                  />
                </label>
              </div>

              {pdfs.length > 0 && (
                <div className="space-y-2">
                  <h3 className="font-semibold text-gray-700">Uploaded Materials:</h3>
                  {pdfs.map((pdf, index) => (
                    <div key={index} className="flex justify-between items-center bg-gray-50 p-3 rounded-lg">
                      <a href={pdf.url} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline truncate">
                        {pdf.name}
                      </a>
                      <button
                        onClick={() => handleRemovePdf(index)}
                        className="bg-red-600 text-white px-3 py-1 rounded hover:bg-red-700 text-sm"
                      >
                        Remove
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'
import Link from 'next/link'

interface Course {
  id: string
  title: string
  description: string
}

export default function Courses() {
  const [courses, setCourses] = useState<Course[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    fetchCourses()
  }, [])

  const fetchCourses = async () => {
    setLoading(true)
    const { data, error } = await supabase.from('courses').select('*')

    if (!error) {
      setCourses(data || [])
    }
    setLoading(false)
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <h1 className="text-4xl font-bold text-gray-900 mb-8">Courses</h1>

        {loading ? (
          <div className="text-center py-12">Loading courses...</div>
        ) : courses.length === 0 ? (
          <div className="text-center py-12 text-gray-500">No courses found</div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {courses.map((course) => (
              <Link key={course.id} href={`/course/${course.id}`}>
                <div className="bg-white rounded-lg shadow hover:shadow-lg transition cursor-pointer h-full">
                  <div className="bg-blue-500 h-40"></div>
                  <div className="p-4">
                    <h3 className="font-bold text-lg mb-2">{course.title}</h3>
                    <p className="text-gray-600 text-sm mb-4">{course.description}</p>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { courseFramework } from '@/components/CourseFramework'

interface Course {
  id: string
  title: string
  description: string
  video_url?: string
  framework?: string // stored as JSON
}

export default function Dashboard() {
  const [user, setUser] = useState<any>(null)
  const [courses, setCourses] = useState<Course[]>([])
  const [loading, setLoading] = useState(true)
  const [showForm, setShowForm] = useState(false)
  const [formData, setFormData] = useState({
    title: '',
    description: '',
  })
  const router = useRouter()

  useEffect(() => {
    // ensure we know the authenticated user before doing anything
    const init = async () => {
      const { data: { session } } = await supabase.auth.getSession()
      if (!session) {
        router.push('/login')
        return
      }
      setUser(session.user)
      await fetchCourses()
      setLoading(false)
    }
    init()
  }, [router])

  const fetchCourses = async () => {
    const { data, error } = await supabase
      .from('courses')
      .select('*')

    if (!error && data) {
      setCourses(data)
    }
  }

  const handleCreateCourse = async (e: React.FormEvent) => {
    e.preventDefault()
    // ensure we have a logged-in user before inserting
    if (!user || !user.id) {
      console.error('Cannot create course: user not found')
      return
    }

    try {
      const { data, error } = await supabase
        .from('courses')
        .insert({
              title: formData.title,
          description: formData.description,
          instructor_id: user.id,
          framework: JSON.stringify(courseFramework),
        })
        .select()

      if (error) throw error

      if (data && data.length) {
        setCourses([...courses, data[0]])
      }
      setFormData({ title: '', description: '' })
      setShowForm(false)
    } catch (error: any) {
      console.error('Error creating course:', error.message)
    }
  }



  if (loading) return <div className="min-h-screen flex items-center justify-center">Loading...</div>

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <h1 className="text-2xl font-bold">Dashboard</h1>
          <div className="flex gap-4">
            <Link href="/framework" className="text-blue-600 hover:underline font-semibold">
              📚 View Framework
            </Link>
          </div>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-3xl font-bold text-gray-600">Welcome, {user?.email}</h2>
          <button
            onClick={() => setShowForm(!showForm)}
            disabled={!user}
            className="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700 disabled:opacity-50"
          >
            {showForm ? 'Cancel' : 'Create Course'}
          </button>
        </div>

        {showForm && (
          <div className="bg-white p-8 rounded-lg shadow mb-8">
            <form onSubmit={handleCreateCourse} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Course Title
                </label>
                <input
                  type="text"
                  required
                  value={formData.title}
                  onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                  className="w-full px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-black"
                  placeholder="Enter course title"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Course Description
                </label>
                <textarea
                  required
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  className="w-full px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 h-24 text-black"
                  placeholder="Describe your course"
                />
              </div>

              <button
                type="submit"
                className="w-full bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700"
              >
                Create Course
              </button>
            </form>
          </div>
        )}

        <div>
          <h3 className="text-xl font-bold mb-4 text-blue-400">Your Courses ({courses.length})</h3>
          
          {courses.length === 0 ? (
            <div className="bg-white p-8 rounded-lg shadow text-center">
              <p className="text-gray-600">No courses created yet</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {courses.map((course) => (
                <div key={course.id} className="bg-white rounded-lg shadow hover:shadow-lg transition p-6">
                  <h4 className="text-lg font-bold mb-2">{course.title}</h4>
                  <p className="text-gray-600 mb-4">{course.description}</p>
                  {course.video_url && (
                    <div className="mb-4 p-2 bg-green-50 rounded border border-green-200">
                      <p className="text-xs text-green-700 font-semibold">✓ Video added</p>
                    </div>
                  )}
                  <Link
                    href={`/course/${course.id}`}
                    className="text-blue-600 hover:underline font-semibold"
                  >
                    Edit Course →
                  </Link>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'
import Link from 'next/link'

export default function Debug() {
  const [status, setStatus] = useState<{
    supabase: string
    auth: string
    tables: string
    error?: string
  }>({
    supabase: 'checking...',
    auth: 'checking...',
    tables: 'checking...',
  })

  useEffect(() => {
    checkConnection()
  }, [])

  const checkConnection = async () => {
    const result = { supabase: '', auth: '', tables: '', error: '' }

    try {
      // Check Supabase connection
      const { data, error } = await supabase.from('courses').select('count', { count: 'exact' })

      if (error) {
        result.supabase = `❌ Failed: ${error.message}`
        result.error = error.message
      } else if (data) {
        result.supabase = '✅ Supabase connected'
      } else {
        result.supabase = '⚠️ Supabase returned no data'
      }

      // Check auth
      const { data: { session } } = await supabase.auth.getSession()
      if (session) {
        result.auth = `✅ Authenticated as ${session.user.email}`
      } else {
        result.auth = '⚠️ Not authenticated (this is normal for non-logged in users)'
      }

      // Check tables
      result.tables = '✅ Courses table accessible'
    } catch (error: any) {
      result.error = error.message
      result.supabase = `❌ Error: ${error.message}`
    }

    setStatus(result)
  }

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-2xl mx-auto">
        <h1 className="text-3xl font-bold mb-8">🔍 Connection Diagnostic</h1>

        <div className="bg-white rounded-lg shadow p-6 space-y-4">
          <div className="border-l-4 border-blue-500 pl-4 py-2">
            <h3 className="font-semibold">Supabase</h3>
            <p className="text-gray-600">{status.supabase}</p>
          </div>

          <div className="border-l-4 border-green-500 pl-4 py-2">
            <h3 className="font-semibold">Authentication</h3>
            <p className="text-gray-600">{status.auth}</p>
          </div>

          <div className="border-l-4 border-purple-500 pl-4 py-2">
            <h3 className="font-semibold">Database Tables</h3>
            <p className="text-gray-600">{status.tables}</p>
          </div>

          {status.error && (
            <div className="border-l-4 border-red-500 pl-4 py-2 bg-red-50">
              <h3 className="font-semibold text-red-700">Error Details</h3>
              <p className="text-red-600 text-sm font-mono">{status.error}</p>
            </div>
          )}
        </div>

        <div className="mt-8">
          <Link
            href="/login"
            className="inline-block bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700"
          >
            Go to Login
          </Link>
        </div>

        <div className="mt-4 text-sm text-gray-600">
          <p>💡 If Supabase shows an error, check:</p>
          <ul className="list-disc list-inside mt-2 space-y-1">
            <li>.env.local file has NEXT_PUBLIC_SUPABASE_URL</li>
            <li>.env.local file has NEXT_PUBLIC_SUPABASE_ANON_KEY</li>
            <li>Supabase project is running</li>
            <li>Network connection is working</li>
          </ul>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { supabase } from '@/lib/supabase'
import { useRouter } from 'next/navigation'
import Link from 'next/link'

export default function Login() {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const router = useRouter()

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setError(null)

    try {
      const { error } = await supabase.auth.signInWithPassword({
        email,
        password,
      })

      if (error) throw error
      router.push('/dashboard')
    } catch (error: any) {
      setError(error.message)
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md w-full space-y-8">
        <h2 className="text-center text-3xl font-bold text-gray-900">Login to your account</h2>
        
        <form className="mt-8 space-y-6" onSubmit={handleLogin}>
          {error && <div className="bg-red-100 text-red-700 p-3 rounded">{error}</div>}
          
          <input
            type="email"
            placeholder="Email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-black"
            required
          />
          
          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-black"
            required
          />
          
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700 disabled:opacity-50"
          >
            {loading ? 'Logging in...' : 'Login'}
          </button>
        </form>
        
        <p className="text-center">
          Don't have an account?{' '}
          <Link href="/signup" className="text-blue-600 hover:underline">
            Sign up
          </Link>
        </p>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'
import { useRouter } from 'next/navigation'
import Link from 'next/link'

export default function Home() {
  const [user, setUser] = useState<any>(null)
  const [loading, setLoading] = useState(true)
  const router = useRouter()

  useEffect(() => {
    checkUser()
  }, [])

  const checkUser = async () => {
    const result = await supabase.auth.getSession()
    const session = result.data?.session
    setUser(session?.user)
    setLoading(false)
  }

  const handleLogout = async () => {
    await supabase.auth.signOut()
    setUser(null)
    router.refresh()
  }

  if (loading) {
    return <div className="min-h-screen flex items-center justify-center">Loading...</div>
  }

  return (
    <div className="min-h-screen bg-white text-black">
      {/* Navigation */}
      <nav className="bg-gray-100 shadow">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <h1 className="text-2xl font-bold">📚 Course Platform</h1>
          <div className="flex gap-4">
            {user ? (
              <>
                <Link href="/dashboard" className="px-4 py-2 rounded-lg hover:bg-white hover:bg-opacity-20 transition">
                  Dashboard
                </Link>
                <button 
                  onClick={handleLogout}
                  className="px-4 py-2 bg-gray-700 text-white rounded-lg hover:bg-gray-800 transition"
                >
                  Logout
                </button>
              </>
            ) : (
              <>
                <Link href="/login" className="px-4 py-2 rounded-lg hover:bg-white hover:bg-opacity-20 transition">
                  Login
                </Link>
                <Link href="/signup" className="px-4 py-2 bg-white text-blue-600 rounded-lg hover:bg-gray-100 transition font-semibold">
                  Sign Up
                </Link>
              </>
            )}
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 text-center">
